INSERT INTO public.photos VALUES (24198, 'Arrabal 1939', 'En 1911, Albert Bressel Mâ”œâ•‌ller abriâ”œâ”‚ un taller en la calle Policarpo Romea, muy cerca del Coso, donde producir piezas de repuesto para la maquinaria del floreciente sector de las azucareras. Dos aâ”œâ–’os mâ”œأ­s tarde, trasladâ”œâ”‚ la producciâ”œâ”‚n a una nueva gran superficie en la avenida de Cataluâ”œâ–’a, y en 1918 la ampliada empresa fue denominada Maquinista y Fundiciones del Ebro, S.A. En la imagen, aâ”œآ®rea visual centrada en el entorno de esta fâ”œأ­brica en 1939. A la izquierda, la blanca fachada de la estaciâ”œâ”‚n del Norte, su gran plaza de acceso, y el ancho mar de vâ”œآ،as que desde ella se abrâ”œآ،a. De izquierda a derecha, el corte de la avenida de Cataluâ”œâ–’a, con el emboque a la calle Norte, y el solar de la desaparecida harinera de Gavâ”œآ،n, a su izquierda, por donde poco despuâ”œآ®s se abrirâ”œآ،a la nueva calle de Santiago Lapuente. En el irregular trapecio del terreno ocupado por la Maquinista, pocos aâ”œâ–’os despuâ”œآ®s se edificarâ”œآ،an nuevos edificios que conformarâ”œآ،an su identitario perfil, hasta su derribo casi integral a finales de los aâ”œâ–’os 90. En la parte superior, el depâ”œâ”‚sito de locomotoras de la estaciâ”œâ”‚n del Norte, la Nueva Harinera de Solans, y los primeros depâ”œâ”‚sitos de remolacha de la azucarera "vieja", o del Arrabal. Fuente visual: aportaciâ”œâ”‚n personal de Arturo Bressel Viâ”œâ–’uales.', 1939, 1939, 1939, 'Anos 30', 'EL RABAL', 41.66056300, -0.87033200, '0101000020E61000005531957EC2D9EBBF4DF910548DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30184299684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30184299684.webp', 'https://www.flickr.com/photos/zaragozaantigua/30184299684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24200, 'San Juan de la Peâ”œâ–’a 1954', 'Aâ”œآ®rea vista del antiguo entorno de la avenida de San Juan de la Peâ”œâ–’a (antigua carretera de Huesca), a la altura donde se ubicaban los depâ”œâ”‚sitos de la empresa CAMPSA, en primer plano. En el centro de la imagen, la fâ”œأ­brica de la Uniâ”œâ”‚n Alcoholera Espaâ”œâ–’ola. A la derecha, las vâ”œآ،as del ferrocarril que culminaba en la estaciâ”œâ”‚n del Norte. Entre ambas instalaciones, varias dâ”œآ®cadas despuâ”œآ®s se abrirâ”œآ،a la prolongaciâ”œâ”‚n de la calle Valle de Broto. Fuente visual: Arxiu Nacional de Catalunya', 1954, 1954, 1954, 'Anos 50', 'EL RABAL', 41.66580500, -0.87068600, '0101000020E6100000C7B8E2E2A8DCEBBFB341261939D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31647533841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31647533841.webp', 'https://www.flickr.com/photos/zaragozaantigua/31647533841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24206, 'Alcoholera Arrabal 1931', 'Imagen de la "Compaâ”œâ–’â”œآ،a de Alcoholes S.A." del Arrabal, al fondo, en una vista general que captura en primer plano la zona recayente al mar de vâ”œآ،as de la estaciâ”œâ”‚n Norte, muy activa como zona de carga y descarga de mercancâ”œآ،as. Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cariâ”œâ–’o y admiraciâ”œâ”‚n, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.66282300, -0.87110500, '0101000020E6100000003ACC9717E0EBBFB0045262D7D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33570560804.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33570560804.webp', 'https://www.flickr.com/photos/zaragozaantigua/33570560804/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24210, 'Estaciâ”œâ”‚n del Norte 1937', 'Tren de la lâ”œآ،nea del Norte con locomotora engalanada con motivos nazis y fascistas, con motivo de la toma de Bilbao por las tropas franquistas. Estâ”œأ­ situado en la Estaciâ”œâ”‚n del Norte o Arrabal de Zaragoza, el 22 de junio de 1937. Fuente: Foto de Francisco Martâ”œآ،nez Gascâ”œâ”‚n, colecciâ”œâ”‚n de Mariano Rodrâ”œآ،guez, a travâ”œآ®s de www.facebook.com/RevistaTREN/', 1937, 1937, 1937, 'Anos 30', 'EL RABAL', 41.66018100, -0.87206100, '0101000020E6100000ECBE6378ECE7EBBF65389ECF80D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36898404976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36898404976.webp', 'https://www.flickr.com/photos/zaragozaantigua/36898404976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24215, 'Estaciâ”œâ”‚n del Norte 1916', 'Imagen capturada con motivo de la llegada a la ciudad de una excursiâ”œâ”‚n comercial easonense en el râ”œأ­pido del Norte, en cuya estaciâ”œâ”‚n se congregâ”œâ”‚ buen nâ”œâ•‘mero de autoridades y representantes para recibir a los expedicionarios.', 1916, 1916, 1916, 'Anos 10', 'EL RABAL', 41.66015200, -0.87205000, '0101000020E6100000F241CF66D5E7EBBFCA3159DC7FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53495184403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53495184403.webp', 'https://www.flickr.com/photos/zaragozaantigua/53495184403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24442, 'Azucarera del Arrabal 1912', 'Imagen del camino de acceso a la puerta principal de la Azucarera de Aragâ”œâ”‚n o del Arrabal (1893). Fuente visual: El fotâ”œâ”‚grafo Luis Gandâ”œâ•‘ Mercadal.', 1912, 1912, 1912, 'Anos 10', 'EL RABAL', 41.66350700, -0.86804800, '0101000020E610000071766B990CC7EBBF63D520CCEDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15031866124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15031866124.webp', 'https://www.flickr.com/photos/zaragozaantigua/15031866124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24491, 'Carretera de Cataluâ”œâ–’a c.1945', 'Tras el "boom" de 1936-1939, cuando la militarizaciâ”œâ”‚n de la producciâ”œâ”‚n industrial de Zaragoza la convirtiâ”œâ”‚ en una de las principales madres nutricias abastecedoras del bando nacionalista, el desolador panorama postbâ”œآ®lico, y el manifiesto alineamiento con las potencias del Eje, revirtieron la tendencia, sâ”œâ”‚lo rota por esporâ”œأ­dicos nuevos proyectos de corte industrial, como el de "Talleres Jordâ”œأ­". La cercanâ”œآ،a de la estaciâ”œâ”‚n del Norte, y el acceso tranviario, orientaron su ubicaciâ”œâ”‚n en el "polo de desarrollo" (avant la lettre) de la carretera de Cataluâ”œâ–’a, junto a la Sociedad Maquinista, como fundiciâ”œâ”‚n orientada a la producciâ”œâ”‚n de mâ”œأ­quinas herramienta, suministro de piezas a ENASA (Empresa Nacional de Autocamiones, S.A.), e incluso, el desarrollo aventurero de proyectos como el del microcoche "Sider". A mediados de los aâ”œâ–’os 50, Talleres Jordâ”œأ­ era la sâ”œآ®ptima empresa del metal en la ciudad, ocupando a 204 trabajadores. Una dâ”œآ®cada mâ”œأ­s tarde, sin embargo, la encontramos en suspensiâ”œâ”‚n de pagos, y embargada, y en los aâ”œâ–’os 70 este entorno fabril fue derribado, vendido, y sobre su solar se levantaron varios altos bloques de viviendas. Los actuales. En el dibujo promocional, a la izquierda, la fachada a la carretera de Cataluâ”œâ–’a, con las vâ”œآ،as de la tranviaria lâ”œآ،nea del Gâ”œأ­llego. Fuente visual: www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'EL RABAL', 41.66081100, -0.86881900, '0101000020E6100000EE96E4805DCDEBBF25EB707495D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25066475153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25066475153.webp', 'https://www.flickr.com/photos/zaragozaantigua/25066475153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24494, 'Vista Arrabal 1991', 'Foto: Rafael Margalâ”œآ®. Vista aâ”œآ®rea del conjunto de edificaciones fabriles junto a la Estaciâ”œâ”‚n del Norte (abajo a la izquierda) en el Arrabal. Arriba a la derecha, Azucarera del Arrabal. Fuente: www.facebook.com/photo.php?fbid=1691428257747540&set=...', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66086400, -0.87125700, '0101000020E610000080272D5C56E1EBBF478D093197D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27997746345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27997746345.webp', 'https://www.flickr.com/photos/zaragozaantigua/27997746345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24495, 'Alcoholera Ebro 1924', 'Junto a los grandes "Talleres de Izuzquiza-Arana", al norte de la estaciâ”œâ”‚n del Arrabal, donde la calle de Sobrarbe continuaba ya como carretera de Francia, en 1911 fue constituida la "Azucarera del Ebro S.A.", pronto asociada con la "Compaâ”œâ–’â”œآ،a de Alcoholes de Bilbao S.A." a la que en 1923 absorbiâ”œâ”‚ conformando una gran empresa denominada "Ebro Compaâ”œâ–’â”œآ،a de Azâ”œâ•‘cares y Alcoholes", por su siglas, "ECAYA". En el plano topogrâ”œأ­fico de 1933, esta fâ”œأ­brica aparece denominada como "Compaâ”œâ–’â”œآ،a de Alcoholes de Aragâ”œâ”‚n". Asâ”œآ، las cosas, la fotografâ”œآ،a muestra una vista parcial de las pequeâ”œâ–’as instalaciones referidas, entre el depâ”œâ”‚sito de locomotoras de la estaciâ”œâ”‚n Norte, que queda justo detrâ”œأ­s, y el acceso desde la carretera de Huesca, desde donde se ha capturado la imagen. Esta fâ”œأ­brica enlazaba con el ferrocarril mediante un apartadero propio, y el tranvâ”œآ،a "Arrabal" tenâ”œآ،a entonces su â”œâ•‘ltima parada justo al lado. Con el tiempo, los edificios de la imagen fueron recredidos en altura, y esta industria estuvo activa hasta que en 1971 cesâ”œâ”‚ en su actividad. Mâ”œأ­s tarde, fue derribada, y el entorno reurbanizado. No perdura ninguna huella edilicia. Fuente visual: Francisco Gâ”œâ”‚rriz, Archivo Municipal de Zaragoza', 1924, 1924, 1924, 'Anos 20', 'EL RABAL', 41.66335000, -0.87212000, '0101000020E61000002A00C63368E8EBBF9BE61DA7E8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28574018751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28574018751.webp', 'https://www.flickr.com/photos/zaragozaantigua/28574018751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24498, 'Valle de Zuriza 1982', 'Recientes bloques de viviendas construidas entre la calle del Valle de Zuriza, desde donde se ha capturado esta imagen, la paralela de los Almadieros del Roncal, y la perpendicular del Valle del Roncal. Al fondo, la avenida de San Juan de la Peâ”œâ–’a, y tras el desecado mar de vâ”œآ،as de la antigua estaciâ”œâ”‚n del Arrabal, el emblemâ”œأ­tico edificio de carpinterâ”œآ،a y almacâ”œآ®n de modelos, rematado en torre, de la metalâ”œâ•‘rgica Maquinista y Fundiciones del Ebro, S.A. Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1982, 1982, 1982, 'Anos 80', 'EL RABAL', 41.66215000, -0.87489200, '0101000020E61000006806F1811DFFEBBFF085C954C1D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30408649890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30408649890.webp', 'https://www.flickr.com/photos/zaragozaantigua/30408649890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24499, 'La Nueva Harinera 1917', 'Cabecera de una factura de "La Nueva Harinera" de la familia Solâ”œأ­ns, construida en 1910 en la calle Arrabal 260, junto a la estaciâ”œâ”‚n del Norte. La ilustraciâ”œâ”‚n reproduce las instalaciones de la fâ”œأ­brica. Fuente: www.todocoleccion.net', 1917, 1917, 1917, 'Anos 10', 'EL RABAL', 41.66204400, -0.87001200, '0101000020E6100000E814E46723D7EBBFAB4198DBBDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30607099125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30607099125.webp', 'https://www.flickr.com/photos/zaragozaantigua/30607099125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24508, 'Av. de Cataluâ”œâ–’a 1948', 'Dibujo promocional de las nuevas instalaciones de los talleres de "Marino Goâ”œâ–’i S.A." en la avenida de Cataluâ”œâ–’a. Esta empresa naciâ”œâ”‚ como distribuidora de maquinaria centroeuropea para la industria molinera y harinera, y con la denominaciâ”œâ”‚n "Bednars y Goâ”œâ–’i", una sucursal se instalâ”œâ”‚ en Zaragoza hacia 1932, con oficinas y talleres en el camino de San Josâ”œآ®. En 1934 participâ”œâ”‚ con stand propio en la I Feria de Muestras Regional Aragonesa, celebrada en la Lonja. La vitalidad del sector harinero permitiâ”œâ”‚ ampliar negocio e instalaciones, de forma que hacia 1945 se inaugurâ”œâ”‚ la planta del dibujo, en una despejada zona donde pocos aâ”œâ–’os despuâ”œآ®s se levantarâ”œآ،a, al otro lado de la avenida, el grupo de viviendas Parcelaciâ”œâ”‚n Damâ”œأ­n. En 1952, tenâ”œآ،a 85 empleados, y era la 16â”¬â•‘ empresa del sector del metal de la ciudad. En el dibujo, una unidad de la serie 40 transita por la lâ”œآ،nea 9, o "Gâ”œأ­llego", hacia el final de la avenida de Cataluâ”œâ–’a. A mediados de la primera dâ”œآ®cada del presente siglo, en este emplazamiento se ubicâ”œâ”‚ la empresa "Qualimax International", hasta que en 2007 se trasladâ”œâ”‚ a PLAZA. Desde entonces, este espacio permanece en barbecho. Fuente visual: harineras.blogspot.com.es/', 1948, 1948, 1948, 'Anos 40', 'EL RABAL', 41.66332800, -0.86261800, '0101000020E6100000151C5E10919AEBBFB34291EEE7D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32047687261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32047687261.webp', 'https://www.flickr.com/photos/zaragozaantigua/32047687261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24512, 'Av. de Cataluâ”œâ–’a 1945', 'Dibujo del proyecto arquitectâ”œâ”‚nico de Alberto Huertas representando la fachada de la nueva fâ”œأ­brica de relojes de los hermanos Coll, sita en la avenida de Cataluâ”œâ–’a, junto a la calle Mallorca, y frente al nuevo convento de San Josâ”œآ® de las MM. Carmelitas Descalzas. Trasladada desde Lascellas (Huesca), esta prestigiosa empresa se especializâ”œâ”‚ de forma destacada en la fabricaciâ”œâ”‚n de relojes para las torres de las iglesias de los nuevos pueblos construidos por el Instituto Nacional de Colonizaciâ”œâ”‚n, en Aragâ”œâ”‚n, Galicia y Extremadura. La inmediata parada del tranvâ”œآ،a "Gâ”œأ­llego" a esta fâ”œأ­brica parece ser que era denominada, por ello, "parada del reloj". Estuvo activa hasta finales de los aâ”œâ–’os setenta. Mâ”œأ­s tarde fue derribada. Fuente visual: Joaquâ”œآ،n Coll Clavero, "En torno a la relojerâ”œآ،a de Lascellas (1870-1978)", Centro de Estudios del Somontano de Barbastro, 2014.', 1945, 1945, 1945, 'Anos 40', 'EL RABAL', 41.66561200, -0.85659900, '0101000020E61000006729594E4269EBBF9FE925C632D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33952731214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33952731214.webp', 'https://www.flickr.com/photos/zaragozaantigua/33952731214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24513, 'Av. de la Jota 1963', 'Vista aâ”œآ®rea de la empresa Amado Laguna de Rins S.A. en sus nuevas instalaciones de la avenida de la Jota 34-42. Fundada en 1880 en el camino de los Cubos por Amado Laguna de Rins, comenzâ”œâ”‚ produciendo materiales topogrâ”œأ­ficos de precisiâ”œâ”‚n, a los que se sumâ”œâ”‚ luego la estampaciâ”œâ”‚n y tornillerâ”œآ،a. Entre 1936-39 produjo materiales de guerra para los nacionalistas. En 1962 fue trasladada a esta ubicaciâ”œâ”‚n, donde ademâ”œأ­s de las producciones tradicionales (material de guerra, material de topografâ”œآ،a y telegrafâ”œآ،a, metalisterâ”œآ،a, tornillerâ”œآ،a, estampaciones, fundiciâ”œâ”‚n de toda clase de metales), iniciâ”œâ”‚ la fabricaciâ”œâ”‚n de materiales auxiliares para la industria del automâ”œâ”‚vil, siempre asociada a dos de las mâ”œأ­s destacadas familias del poder polâ”œآ،tico local: los Laguna de Rins y los Almarza Laguna de Rins. En la imagen, la gran factorâ”œآ،a fabril centra la captura. Al sur, la avenida de la Jota y una vista parcial del Grupo de Viviendas de la Parcelaciâ”œâ”‚n Daman. Tras su cierre y desmantelamiento, su solar serâ”œأ­ remodelado y urbanizado en torno a los nuevos viales de Balbino Orensanz, Felisa Galâ”œآ®, Baluarte Aragonâ”œآ®s y Velilla de Ebro. Fuente visual: revista "Aragâ”œâ”‚n turâ”œآ،stico y monumental", SIPA.', 1963, 1963, 1963, 'Anos 60', 'EL RABAL', 41.66111600, -0.85953900, '0101000020E6100000925ED4EE5781EBBF616EF7729FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34393069760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34393069760.webp', 'https://www.flickr.com/photos/zaragozaantigua/34393069760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24514, 'Alcoholera Arrabal 1931', 'Imagen de la "Compaâ”œâ–’â”œآ،a de Alcoholes de Aragâ”œâ”‚n" del Arrabal, centrada en los edificios de la fâ”œأ­brica, a la izquierda, almacenes, a la derecha, y en los barriles preparados para ser embarcados en el apeadero ferroviario que enlazaba con el mar de vâ”œآ،as de la estaciâ”œâ”‚n Norte, cuyo depâ”œâ”‚sito de locomotoras queda justo detrâ”œأ­s. Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cariâ”œâ–’o y admiraciâ”œâ”‚n, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.66335000, -0.87212000, '0101000020E61000002A00C63368E8EBBF9BE61DA7E8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34393330675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34393330675.webp', 'https://www.flickr.com/photos/zaragozaantigua/34393330675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24520, 'Arrabal 1910', 'Imagen de la fachada norte de la Nueva Harinera de Zaragoza, denominaciâ”œâ”‚n de la fâ”œأ­brica de harinas de Hijos y Sobrino de Juan Solans en el Arrabal, junto a la Estaciâ”œâ”‚n del Norte (a la derecha, fuera de plano), con capacidad de moler cuarenta toneladas de trigo al dâ”œآ،a. Al fondo, a la izquierda, barroca torre de la Seo en la margen derecha del râ”œآ،o Ebro. Fuente visual: www.todocoleccion.net/', 1910, 1910, 1910, 'Anos 10', 'EL RABAL', 41.66204400, -0.87001200, '0101000020E6100000E814E46723D7EBBFAB4198DBBDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39177625765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39177625765.webp', 'https://www.flickr.com/photos/zaragozaantigua/39177625765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24536, 'Azucarera del Arrabal 1995', 'Las abandonadas desde el aâ”œâ–’o 1966 y enormes instalaciones de la antigua Azucarera de Aragâ”œâ”‚n, o del Arrabal, en una imagen capturada desde sus traseras recayentes al tambiâ”œآ®n desmantelado y abandonado tendido ferroviario que desde la estaciâ”œâ”‚n del Arrabal condujera hacia norteâ”œâ–’os destinos. Al fondo y a la derecha, una leve vista de los grandes bloques de la avenida de Cataluâ”œâ–’a a la altura de la calle de los Jardines Aguilar de Ebro, pioneros en la moderna urbanizaciâ”œâ”‚n de esta extensa y antigua zona industrial de la ciudad.', 1995, 1995, 1995, 'Anos 90', 'EL RABAL', 41.66437600, -0.86914300, '0101000020E6100000B68311FB04D0EBBFA71FD4450AD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50433614616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50433614616.webp', 'https://www.flickr.com/photos/zaragozaantigua/50433614616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24538, 'Harinas Solans S.A., 1938', 'Dibujo de la fâ”œأ­brica Harinas Solans S.A. donde su perâ”œآ،metro delimitado entre la avenida de Cataluâ”œâ–’a, a la izquierda, y el depâ”œâ”‚sito de mâ”œأ­quinas locomotoras de la estaciâ”œâ”‚n del Arrabal, a la derecha, se centra en el gran edificio central construido con proyecto del arquitecto Miguel â”œأ¼ngel Navarro Pâ”œآ®rez al comienzo de la dâ”œآ®cada de 1910. A la derecha, un convoy ferroviario seâ”œâ–’ala la presencia del apartadero propio que conectaba a la factorâ”œآ،a con la estaciâ”œâ”‚n del Arrabal.', 1938, 1938, 1938, 'Anos 30', 'EL RABAL', 41.66152300, -0.86935700, '0101000020E6100000B98E71C5C5D1EBBFA24621C9ACD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50600959053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50600959053.webp', 'https://www.flickr.com/photos/zaragozaantigua/50600959053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24744, 'Cincomarzada 1991', 'Foto Rogelio Allepuz, 1991. Celebraciâ”œâ”‚n de la Cincomarzada, el 5 de marzo de 1991, en el parque del Tâ”œآ،o Jorge de Zaragoza. En primer plano, peâ”œâ–’istas y rancho. Al fondo, internacionalistas. Fuente: www.facebook.com/photo.php?fbid=573197456109890&set=p...', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66409300, -0.87669800, '0101000020E6100000D6FECEF6E80DECBF5340DAFF00D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15665639998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15665639998.webp', 'https://www.flickr.com/photos/zaragozaantigua/15665639998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24746, 'Calle Villacampa 1990', 'Foto Galagar, 1990. Calle de Pedro Villacampa, en el barrio del Arrabal de Zaragoza. Hacia el fondo, direcciâ”œâ”‚n Sixto Celorrio; a la espalda, direcciâ”œâ”‚n Sobrarbe. A la izquierda queda la plaza del Rosario, fuera de la toma. Fuente: www.facebook.com/photo.php?fbid=973598639333260&set=o...', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.66027900, -0.87478700, '0101000020E610000014E97E4E41FEEBBF289EB30584D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15728601996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15728601996.webp', 'https://www.flickr.com/photos/zaragozaantigua/15728601996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24748, 'Monumento al Tâ”œآ،o Jorge 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1968. Instalaciâ”œâ”‚n del "Monumento al Tâ”œآ،o Jorge", de â”œأ¼ngel Orensanz, en el Parque del Tâ”œآ،o Jorge. La realizaciâ”œâ”‚n de la obra estaba relacionada con la construcciâ”œâ”‚n del Parque del Tâ”œآ،o Jorge en el Rabal, y la voluntad de que fuera su principal seâ”œâ–’a de identidad. El monumento se compone de dos elementos independientes: la realista escultura en piedra del Tâ”œآ،o Jorge, y un gran monolito en hormigâ”œâ”‚n y hierro de carâ”œأ­cter surrealista y simbâ”œâ”‚lico. En la imagen, operarios municipales ultiman faenas antes de la inauguraciâ”œâ”‚n en la glorieta en que se instalâ”œâ”‚ el monumento, cerca del lâ”œآ،mite norte del parque del Tâ”œآ،o Jorge, junto a lo que pocos aâ”œâ–’os despuâ”œآ®s se denominarâ”œأ­ Valle de Broto (detrâ”œأ­s de los â”œأ­rboles). Fuente: www.zaragoza.es/ciudad/artepublico/detalle_ArtePublico?id=46', 1968, 1968, 1968, 'Anos 60', 'EL RABAL', 41.66522100, -0.87658300, '0101000020E61000009F58A7CAF70CECBF64CE33F625D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15796863045.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15796863045.webp', 'https://www.flickr.com/photos/zaragozaantigua/15796863045/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24750, 'Calle Molino de las Armas 1977', 'Vista de la calle Molino de Las Armas en el barrio de la Jota de Zaragoza, tramo comprendido entre Pascuala Periâ”œآ® (tras el fotâ”œâ”‚grafo) y Marquâ”œآ®s de la Cadena (al fondo). Con una enorme torre elâ”œآ®ctrica en la acera de los pares y una pancarta reivindicativa de su desapariciâ”œâ”‚n. Al fondo, la torre de la Seo. Fuente: La orilla izquierda del Ebro zaragozano, Marâ”œآ،a Carmen Faus, 1988.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66109600, -0.86342500, '0101000020E6100000C58F31772DA1EBBF1AC231CB9ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18620703834.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18620703834.webp', 'https://www.flickr.com/photos/zaragozaantigua/18620703834/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24751, 'Calle Villacampa 1977', 'Vista de la calle de Pedro Villacampa en 1988. Al fondo, la calle Sobrarbe. La toma estâ”œأ­ hecha desde la plaza del Rosario. Fuente: La orilla izquierda del Ebro zaragozano, Marâ”œآ،a Carmen Faus, 1988.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66015900, -0.87452900, '0101000020E610000029EACC3D24FCEBBF7D94111780D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18998193180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18998193180.webp', 'https://www.flickr.com/photos/zaragozaantigua/18998193180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24757, 'Azucarera de Aragâ”œâ”‚n 1899', 'Fâ”œأ­brica "La Azucarera de Aragâ”œâ”‚n" en el Camino de las Torrecillas del Arrabal de Zaragoza. Fue la primera azucarera de la regiâ”œâ”‚n y funcionâ”œâ”‚ de 1897 a 1966. Los edificios que perviven y las dos chimeneas que tuvo son hoy dependencias municipales: depâ”œâ”‚sito de bienes embargados a finales del siglo XX y "Zaragoza activa" tras su remozo en 2004, Su domicilio actual es calle Mas de las Matas 20. Fuente: Mâ”¬آ¬ Pilar Biel Ibâ”œأ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1926, IFC, 2004.', 1899, 1899, 1899, 'Siglo XIX', 'EL RABAL', 41.66350700, -0.86804800, '0101000020E610000071766B990CC7EBBF63D520CCEDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19674203876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19674203876.webp', 'https://www.flickr.com/photos/zaragozaantigua/19674203876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24762, 'Calle Sobrarbe 1977', 'Imagen de la calle Sobrarbe con el antiguo arranque de la calle Villacampa, y los locales comerciales establecidos en sus bajos. De izquierda a derecha, los antiguos nâ”œâ•‘meros 49, 51 y 53 de Sobrarbe, y los 1 y 2 de Villacampa, con esa tipologâ”œآ،a de viviendas de los siglos XVII-XVIII, con leves reformas en el XIX, que caracterizaban las calles del "casco viejo" del arrabal de Altabâ”œأ­s, cuando Sobrarbe era "Monjas" y "Tintes", Villacampa era "Tejar", Ibort era "Medio"... Aâ”œâ–’os despuâ”œآ®s, estas casonas serâ”œآ،an derribadas para levantar otras mâ”œأ­s modernas, y la manzana de los pares de Villacampa, retranqueada y alineada con la de los impares. Fuente visual: amable aportaciâ”œâ”‚n del Archivo personal de Pablo Valdâ”œآ®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65998400, -0.87398100, '0101000020E61000007B698A00A7F7EBBF0FF10F5B7AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20110500032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20110500032.webp', 'https://www.flickr.com/photos/zaragozaantigua/20110500032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24764, 'Carretera de Huesca 1862', '"Plano topogrâ”œأ­fico y nivelaciâ”œâ”‚n de la zona comprendida entre la Puerta del â”œأ¼ngel de Zaragoza y la Venta de Tetuâ”œأ­n en la Carretera de Huesca. Alumnos del Instituto de Zaragoza de Agrimensores y Peritos Tasadores de tierras. Curso 1861-1862". A la derecha, el râ”œآ،o Ebro con las plantas de los edificios de la ribera derecha; hacia la izquierda, el Arrabal, la estaciâ”œâ”‚n del Norte y el convento de Jesâ”œâ•‘s; y a la izquierda la Venta de Tetuâ”œأ­n. Fuente: AMZ.', 1862, 1862, 1862, 'Siglo XIX', 'EL RABAL', 41.66265900, -0.87263000, '0101000020E61000007845F0BF95ECEBBF35B39602D2D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20414926034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20414926034.webp', 'https://www.flickr.com/photos/zaragozaantigua/20414926034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24765, 'Estaciâ”œâ”‚n del Norte 1967', 'Estaciâ”œâ”‚n del Norte o del Arrabal, con un tren saliendo direcciâ”œâ”‚n Lâ”œآ®rida. Al fondo, la torre de la Seo. Fuente visual: Colecciâ”œâ”‚n Cristina Rubio en "150 aâ”œâ–’os de ferrocarril en Zaragoza", 2011.', 1967, 1967, 1967, 'Anos 60', 'EL RABAL', 41.66016800, -0.87198600, '0101000020E6100000433C122F4FE7EBBFD0EE906280D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20630121101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20630121101.webp', 'https://www.flickr.com/photos/zaragozaantigua/20630121101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
