INSERT INTO public.photos VALUES (24775, 'TACA c.1966', 'Aâ”œآ®rea vista del moderno complejo fabril de la empresa TACA, inaugurada en 1965 con participaciâ”œâ”‚n de Mann+Hummel, y el Gobierno de Espaâ”œâ–’a, al ser una iniciativa integrada en el Polo de Desarrollo de Zaragoza. Luego denominada Filtros Mann S.A., en 2005 fue trasladada a PLAZA, donde perdura como Mann+Hummel Ibâ”œآ®rica S.A.U., y estas antiguas instalaciones de la avenida de Cataluâ”œâ–’a fueron derribadas. Al fondo se destacan las cuatro torres del templo del Pilar.', 1966, 1966, 1966, 'Anos 60', 'EL RABAL', 41.66485900, -0.85391700, '0101000020E610000028F38FBE4953EBBFC3B986191AD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24578267369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24578267369.webp', 'https://www.flickr.com/photos/zaragozaantigua/24578267369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24778, 'Estaciâ”œâ”‚n del Norte 1977', 'Imagen de la fachada principal de acceso a la antigua estaciâ”œâ”‚n Norte en el Arrabal, que fuera la primera en activo de la ciudad, clausurada en sus funciones ferroviarias un par de aâ”œâ–’os antes de capturar esta fotografâ”œآ،a. En el suelo, inmediatas, las vâ”œآ،as del ramal que la lâ”œآ،nea 4 del tranvâ”œآ،a dispuso, a principios del siglo XX, tendidas desde el otro lado del Ebro. El edificio principal (que sustituyâ”œâ”‚ a unos provisionales anteriores) fue levantado en 1863, posiblemente segâ”œâ•‘n diseâ”œâ–’o del ingeniero Pedro Andrâ”œآ®s y Puigdollers, que venâ”œآ،a de hacer lo propio con la estaciâ”œâ”‚n de Barcelona. Fuente visual: amable aportaciâ”œâ”‚n personal de Pablo Valdâ”œآ®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66004600, -0.87178000, '0101000020E6100000F6D1A92B9FE5EBBF85ED27637CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26520402452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26520402452.webp', 'https://www.flickr.com/photos/zaragozaantigua/26520402452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24783, 'Vista Arrabal 1991', 'Foto: Rafael Margalâ”œآ®. Vista aâ”œآ®rea del Arrabal, partiendo de la confluencia de la calle del Sobrarbe con la avenida de Cataluâ”œâ–’a (abajo a la izquierda). En el centro, complejos fabriles junto a la Estaciâ”œâ”‚n del Norte, aâ”œâ•‘n sin derribar. Fuente: www.facebook.com/photo.php?fbid=1691428254414207&set=...', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66086400, -0.87125700, '0101000020E610000080272D5C56E1EBBF478D093197D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27383444913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27383444913.webp', 'https://www.flickr.com/photos/zaragozaantigua/27383444913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24788, 'Av. de Cataluâ”œâ–’a 1965', 'Imagen aâ”œآ®rea del entronque, en primer tâ”œآ®rmino, de la calle del Alcalde Caballero (tambiâ”œآ®n denominada "Enlace de Carreteras" del norte) con la avenida de Cataluâ”œâ–’a, con interesante perspectiva de la factorâ”œآ،a de deshidrataciâ”œâ”‚n de alfalfa y fabricaciâ”œâ”‚n de piensos compuestos Arquero S.A. (vulgo Piensos Arquero), luego propiedad de Pygasa. Tras ella, el nuevo convento de San Josâ”œآ® de las Carmelitas Descalzas, y casi confrontando, a la derecha de la avenida de Cataluâ”œâ–’a, las instalaciones de la novâ”œآ،sima empresa TACA (Talleres Cataluâ”œâ–’a) Mann S.A. Fuente visual: Arxiu Nacional de Catalunya.', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.66615100, -0.85774600, '0101000020E61000004BCB48BDA772EBBF4E999B6F44D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31057248524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31057248524.webp', 'https://www.flickr.com/photos/zaragozaantigua/31057248524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24789, 'Ricardo del Arco 1933', 'Imagen del interior de la nave siniestrada en el incendio de la arrabalera fâ”œأ­brica de curtidos de Policarpo Aramendâ”œآ،a, sita en la calle de Ricardo del Arco, cerca del camino de las Balsas de Ebro Viejo. La captura se ha realizado cuando los bomberos municipales parecen estar terminando de sofocar el fuego. A la izquierda, algunas piezas de la curtiembre. Fuente visual: Alejandro de la Barrera, en "Revista Ahora" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'EL RABAL', 41.66005800, -0.87741300, '0101000020E61000005ABA826DC413ECBF49BBD1C77CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31766232014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31766232014.webp', 'https://www.flickr.com/photos/zaragozaantigua/31766232014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24808, 'Calle de Santa Fe 1989', 'Complejo fabril de Filtros Mann S.A. en una aâ”œآ®rea vista en altura del entorno de la avenida de Cataluâ”œâ–’a centrada en las instalaciones de esta empresa dedicada a la fabricaciâ”œâ”‚n de filtros para automâ”œâ”‚viles y camiones. Fue inaugurada en 1965 con participaciâ”œâ”‚n de Taca, Mann+Hummel, y el Estado, como una iniciativa integrada en el Polo de Desarrollo de Zaragoza. En 2005 fue trasladada a la Plataforma Logâ”œآ،stica de Zaragoza, Plaza, donde perdura como Mann+Hummel Ibâ”œآ®rica S.A.U. Esta factorâ”œآ،a fue por ello derribada, sin que hasta la fecha esta â”œأ¼rea de intervenciâ”œâ”‚n F-55-5 haya sido desarrollada, salvo un bloque de 45 viviendas en la calle de la Isla Dragonera. En la imagen, la fâ”œأ­brica aparece flanqueada, a la izquierda, por la calle de Santa Fe, que recuerda la homâ”œâ”‚nima barriada, y el tendido ferroviario de Zaragoza a Huesca, a la derecha. Al fondo, el Polâ”œآ،gono de El Pilar, de 1982.', 1989, 1989, 1989, 'Anos 80', 'EL RABAL', 41.66485900, -0.85391700, '0101000020E610000028F38FBE4953EBBFC3B986191AD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34517675850.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34517675850.webp', 'https://www.flickr.com/photos/zaragozaantigua/34517675850/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24811, 'Calle de Santa Fe 1932', 'Imagen capturada en la calle de Santa Fe, en la barriada del mismo nombre, que junto con las barriadas de Costa y de Escudero conformaban la denominada Explanada del Gâ”œأ­llego. Se trataba de tres parcelaciones particulares discontinuas, de urbanizaciâ”œâ”‚n privada, en el entorno de la carretera de Madrid a Francia por la Junquera y en direcciâ”œâ”‚n al puente del Gâ”œأ­llego que, como era costumbre carecâ”œآ،an de servicios e infraestructuras. La mâ”œأ­s cercana a la ciudad era la barriada de Costa, a la izquierda y cercana al camino de las Torrecillas, con viales anâ”œâ”‚nimos que mâ”œأ­s tarde recibirâ”œأ­n los nombres de Aurora, Esquedas, Santa Quiteria y Sierra de Alcubierre. La barriada de Escudero se encontraba a la derecha, articulada en torno a las calles de Escudero (luego Ruiseâ”œâ–’or, y Pedro Lâ”œأ­zaro) y de Liria (luego, Once de Julio). Finalmente, la barriada de Santa Fe, tambiâ”œآ®n a la derecha de la carretera, vertebrada por las paralelas calles de Mallorca y de Santa Fe, que la imagen ilustra.', 1932, 1932, 1932, 'Anos 30', 'EL RABAL', 41.66562800, -0.85563400, '0101000020E6100000AE0FEB8D5A61EBBFA4A65D4C33D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34896993934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34896993934.webp', 'https://www.flickr.com/photos/zaragozaantigua/34896993934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24814, 'San Juan de la Peâ”œâ–’a 1977', 'Imagen capturada desde cierta altura en la calle de San Juan de la Peâ”œâ–’a (antigua carretera de Huesca), centrada en el tramo posterior al cruce con la calle del Marquâ”œآ®s de la Cadena. En primer tâ”œآ®rmino, modernas instalaciones de Hierros Alfonso SA. Detrâ”œأ­s, a la derecha, la antigua fâ”œأ­brica de la Uniâ”œâ”‚n Alcoholera Espaâ”œâ–’ola, y al fondo y a la izquierda el creciente recinto de la veterana papelera Sociedad Anâ”œâ”‚nima Industrias Celulosa Aragonesa (SAICA).', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66725500, -0.87115800, '0101000020E6100000B5C2F4BD86E0EBBFD68BA19C68D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39856865572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39856865572.webp', 'https://www.flickr.com/photos/zaragozaantigua/39856865572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24815, 'Picarral 1965', 'Aâ”œآ®rea visual parcial del barrio del Picarral con detalle de la zona comprendida entre la avenida de San Juan de la Peâ”œâ–’a, el antiguo camino de Juslibol y los terrenos de cultivo por donde poco despuâ”œآ®s serâ”œآ،a trazada la nueva avenida de los Pirineos. Desde la parte inferior derecha encontramos vistas de los grupos de viviendas "Balsas de Ebro Viejo", del "Teniente Polanco", del "General Franco", y el de San Juan de la Peâ”œâ–’a 181-195, ademâ”œأ­s de las empresas TACA y CAITASA, el colegio de San Braulio y la parroquia de Belâ”œآ®n. Fuente visual: TAF Helicâ”œâ–“pters SA, en Arxiu Nacional de Catalunya.', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.66847400, -0.87459200, '0101000020E6100000C2FBAA5CA8FCEBBFF81C588E90D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40662952280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40662952280.webp', 'https://www.flickr.com/photos/zaragozaantigua/40662952280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24822, 'Av. de Cataluâ”œâ–’a 1991', 'Imagen en altura .desde la calle del Marquâ”œآ®s de la Cadena centrada en el gran solar dejado tras el derribo de la Casa Cuartel de la Guardia Civil sita en la avenida de Cataluâ”œâ–’a (a la derecha) y que fue objeto de terrible atentado terrorista el 11 de diciembre de 1987. A la izquierda, la calle de Josâ”œآ® Oto. El Ayuntamiento acordâ”œâ”‚ ubicar sobre este solar una nueva plaza-parque cuyo elemento central serâ”œآ،a un grupo escultâ”œâ”‚rico que en principio iba a denominarse "Juego de niâ”œâ–’os", y finalmente serâ”œآ،a "Monumento a los niâ”œâ–’os", con diseâ”œâ–’o del tallista aragonâ”œآ®s Carlos Pâ”œآ®rez de Albâ”œآ®niz Navarro para homenajear a la infancia como sâ”œآ،mbolo de la paz. En paralelo, un nuevo cuartel de la Guardia Civil fue ubicado en el barrio de Casetas. En 1992 serâ”œآ،a inaugurado el Parque de la Esperanza, tras una inversiâ”œâ”‚n de casi 36 millones de pesetas.', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66141800, -0.86523700, '0101000020E6100000BC40498105B0EBBF2C7E5358A9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50378156076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50378156076.webp', 'https://www.flickr.com/photos/zaragozaantigua/50378156076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24824, 'Azucarera de Aragâ”œâ”‚n 1899', 'Imagen de la Azucarera de Aragâ”œâ”‚n capturada junto al ramal ferroviario que enlazaba con la estaciâ”œâ”‚n del Norte y por el que transitaban tambiâ”œآ®n vagonetas de mercancâ”œآ،as a tracciâ”œâ”‚n de sangre de la lâ”œآ،nea Arrabal-Estaciâ”œâ”‚n, por donde se transportaba hasta aquâ”œآ، la remolacha azucarera de que se surtâ”œآ،a esta fâ”œأ­brica, que fue la primera azucarera de la regiâ”œâ”‚n y que estuvo activa desde 1897 y hasta 1966. Los edificios que aquâ”œآ، figuran son los originales que fueron proyectados por Luis Aladrâ”œآ®n en 1893, entre los que destacan el horno de cal, el secadero de pulpas, el cuarto de calderas y la gran chimenea, ademâ”œأ­s de la torre de filtros, la estructura de mâ”œأ­s altura (seis pisos) tras la chimenea. A la derecha, la nave de falsos pisos y tejado a doble vertiente donde se encontraba la zona de lavado, difusiâ”œâ”‚n, evaporizaciâ”œâ”‚n, cristalizaciâ”œâ”‚n y turbinaciâ”œâ”‚n. Al fondo y a la derecha, la casa del director de la fâ”œأ­brica, inmediata al acceso desde el camino de las Torrecillas.', 1899, 1899, 1899, 'Siglo XIX', 'EL RABAL', 41.66347800, -0.86888500, '0101000020E6100000CB845FEAE7CDEBBFC8CEDBD8ECD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50399927348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50399927348.webp', 'https://www.flickr.com/photos/zaragozaantigua/50399927348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25102, 'Av. de Cataluâ”œâ–’a 1992', 'Imagen capturada durante la inauguraciâ”œâ”‚n oficial del parque de la Esperanza el 21 de mayo de 1992 por el director general de la Guardia Civil, Luis Roldâ”œأ­n y el alcalde de Zaragoza, Antonio Gonzâ”œأ­lez Triviâ”œâ–’o. En primer tâ”œآ®rmino, figura del niâ”œâ–’o con monopatâ”œآ،n integrante del Monumento a los niâ”œâ–’os, como recuerdo a las vâ”œآ،ctimas, especialmente las infantiles, del atentado terrorista contra la Casa Cuartel de la Guardia Civil en la avenida de Cataluâ”œâ–’a el 11 de diciembre de 1987. Al fondo, entorno de la plaza de W. Amadeus Mozart donde se cruzan la avenida de Cataluâ”œâ–’a y la calle del Marquâ”œآ®s de la Cadena.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.66131400, -0.86538700, '0101000020E61000000F46EC1340B1EBBF8731E9EFA5D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50451350938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50451350938.webp', 'https://www.flickr.com/photos/zaragozaantigua/50451350938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25965, 'ACTUR 1982', 'Visual aâ”œآ®rea centrada en el â”œأ¼rea de Actuaciâ”œâ”‚n Urbanâ”œآ،stica Urgente en los barrios de Zalfonada y Picarral.', 1982, 1982, 1982, 'Anos 80', 'EL RABAL', 41.66847100, -0.87659200, '0101000020E61000006CED7DAA0A0DECBF86A92D7590D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701394097.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701394097.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701394097/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26030, 'Vista barrio La Jota 1955', 'Vista aâ”œآ®rea centrada en el Grupo de Viviendas Parcelaciâ”œâ”‚n Daman, en el barrio de La Jota, con la avenida de Cataluâ”œâ–’a a la izquierda y el Ebro y el Pilar al fondo. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'EL RABAL', 41.66248600, -0.86103600, '0101000020E61000008DB7955E9B8DEBBF68075C57CCD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30538225114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30538225114.webp', 'https://www.flickr.com/photos/zaragozaantigua/30538225114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
